Set-StrictMode -Version Latest
$ErrorActionPreference = "Stop"

function Get-ExperimentRepoRoot {
    return (Resolve-Path (Join-Path $PSScriptRoot "..")).Path
}

function Get-ExperimentConfigPath {
    param(
        [string]$ConfigPath = "config/experiment.example.json"
    )

    if ([System.IO.Path]::IsPathRooted($ConfigPath)) {
        return $ConfigPath
    }

    $repoRoot = Get-ExperimentRepoRoot
    return (Join-Path $repoRoot $ConfigPath)
}

function Assert-ExperimentRequiredKeys {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Context,

        [Parameter(Mandatory = $true)]
        $Value,

        [Parameter(Mandatory = $true)]
        [string[]]$RequiredKeys
    )

    $propertyNames = @()
    if ($null -ne $Value) {
        $propertyNames = @($Value.PSObject.Properties.Name)
    }

    foreach ($requiredKey in $RequiredKeys) {
        if (-not $propertyNames.Contains($requiredKey)) {
            throw "$Context is missing required key '$requiredKey'."
        }
    }
}

function Read-ExperimentConfig {
    param(
        [string]$ConfigPath = "config/experiment.example.json"
    )

    $resolvedConfigPath = Get-ExperimentConfigPath -ConfigPath $ConfigPath
    if (-not (Test-Path -LiteralPath $resolvedConfigPath)) {
        throw "Experiment config not found: $resolvedConfigPath"
    }

    $config = Get-Content -LiteralPath $resolvedConfigPath -Raw | ConvertFrom-Json
    Assert-ExperimentRequiredKeys -Context "Experiment config" -Value $config -RequiredKeys @(
        "paths",
        "runtime",
        "entryScripts",
        "prerequisites"
    )

    return $config
}

function Resolve-ExperimentPath {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Path
    )

    if ([System.IO.Path]::IsPathRooted($Path)) {
        return $Path
    }

    return (Join-Path (Get-ExperimentRepoRoot) $Path)
}

function Get-ExperimentPaths {
    param(
        [Parameter(Mandatory = $true)]
        $Config
    )

    $resolved = [ordered]@{}
    foreach ($property in $Config.paths.PSObject.Properties) {
        $resolved[$property.Name] = Resolve-ExperimentPath -Path $property.Value
    }

    return [pscustomobject]$resolved
}

function Get-ExperimentRuntimeDefaults {
    param(
        [Parameter(Mandatory = $true)]
        $Config
    )

    return $Config.runtime
}

function Get-ExperimentEntryScripts {
    param(
        [Parameter(Mandatory = $true)]
        $Config
    )

    $resolved = [ordered]@{}
    foreach ($property in $Config.entryScripts.PSObject.Properties) {
        $resolved[$property.Name] = Resolve-ExperimentPath -Path $property.Value
    }

    return [pscustomobject]$resolved
}

function Resolve-ExperimentProfilePath {
    param(
        [string]$ProfileName = "",
        [string]$ConfigPath = "config/experiment.example.json"
    )

    $config = Read-ExperimentConfig -ConfigPath $ConfigPath
    $paths = Get-ExperimentPaths -Config $config
    $profileReference = if ([string]::IsNullOrWhiteSpace($ProfileName)) {
        $config.runtime.defaultProfile
    }
    else {
        $ProfileName
    }

    if ([string]::IsNullOrWhiteSpace($profileReference)) {
        throw "Experiment runtime.defaultProfile must be configured before resolving a profile."
    }

    if ([System.IO.Path]::IsPathRooted($profileReference)) {
        return $profileReference
    }

    $isRelativePath = $profileReference.Contains([System.IO.Path]::DirectorySeparatorChar) `
        -or $profileReference.Contains([System.IO.Path]::AltDirectorySeparatorChar) `
        -or $profileReference.EndsWith(".json")
    if ($isRelativePath) {
        return Resolve-ExperimentPath -Path $profileReference
    }

    return (Join-Path $paths.profilesRoot "$profileReference.json")
}

function Read-ExperimentProfile {
    param(
        [string]$ProfileName = "",
        [string]$ConfigPath = "config/experiment.example.json"
    )

    $resolvedProfilePath = Resolve-ExperimentProfilePath -ProfileName $ProfileName -ConfigPath $ConfigPath
    if (-not (Test-Path -LiteralPath $resolvedProfilePath)) {
        throw "Experiment profile not found: $resolvedProfilePath"
    }

    $profileData = Get-Content -LiteralPath $resolvedProfilePath -Raw | ConvertFrom-Json
    Assert-ExperimentRequiredKeys -Context "Experiment profile" -Value $profileData -RequiredKeys @(
        "id",
        "source",
        "target",
        "workspace",
        "environment",
        "prerequisites",
        "verification"
    )
    Assert-ExperimentRequiredKeys -Context "Experiment profile source" -Value $profileData.source -RequiredKeys @(
        "kind"
    )

    switch ($profileData.source.kind) {
        "remoteGit" {
            Assert-ExperimentRequiredKeys -Context "Experiment profile source" -Value $profileData.source -RequiredKeys @(
                "repositoryUrl",
                "defaultBranch",
                "checkoutPath"
            )
        }
        "fixtureSeed" {
            Assert-ExperimentRequiredKeys -Context "Experiment profile source" -Value $profileData.source -RequiredKeys @(
                "seedRoot"
            )
        }
        default {
            throw "Experiment profile source kind '$($profileData.source.kind)' is not supported."
        }
    }

    Assert-ExperimentRequiredKeys -Context "Experiment profile target" -Value $profileData.target -RequiredKeys @(
        "kind",
        "repositoryPath"
    )
    Assert-ExperimentRequiredKeys -Context "Experiment profile workspace" -Value $profileData.workspace -RequiredKeys @(
        "path"
    )
    Assert-ExperimentRequiredKeys -Context "Experiment profile environment" -Value $profileData.environment -RequiredKeys @(
        "required",
        "optional"
    )
    Assert-ExperimentRequiredKeys -Context "Experiment profile prerequisites" -Value $profileData.prerequisites -RequiredKeys @(
        "overlays"
    )
    Assert-ExperimentRequiredKeys -Context "Experiment profile verification" -Value $profileData.verification -RequiredKeys @(
        "phases"
    )

    return $profileData
}

function Normalize-ExperimentProfile {
    <#
    """Normalize a declarative experiment profile for either fixture or remote targets into immutable metadata: source checkout, mutable target repo path, workspace path, environment requirements, prerequisite overlays, and ordered verification phases. This helper defines discovery and validation only; downstream scripts perform cloning, installation, and verification without changing the profile shape."""
    #>
    param(
        [string]$ProfileName = "",
        [string]$ConfigPath = "config/experiment.example.json"
    )

    $config = Read-ExperimentConfig -ConfigPath $ConfigPath
    $entryScripts = Get-ExperimentEntryScripts -Config $config
    $profileData = Read-ExperimentProfile -ProfileName $ProfileName -ConfigPath $ConfigPath
    $repoRoot = Get-ExperimentRepoRoot

    $requiredEnvironment = @($profileData.environment.required)
    $optionalEnvironment = @($profileData.environment.optional)
    $prerequisiteOverlays = [ordered]@{}
    foreach ($property in $profileData.prerequisites.overlays.PSObject.Properties) {
        $prerequisiteOverlays[$property.Name] = $property.Value
    }

    $normalizedPhases = @()
    foreach ($phase in @($profileData.verification.phases)) {
        Assert-ExperimentRequiredKeys -Context "Verification phase" -Value $phase -RequiredKeys @("id")

        $hasEntryScript = $phase.PSObject.Properties.Name.Contains("entryScript") -and -not [string]::IsNullOrWhiteSpace($phase.entryScript)
        $hasCommand = $phase.PSObject.Properties.Name.Contains("command") -and -not [string]::IsNullOrWhiteSpace($phase.command)
        if (-not $hasEntryScript -and -not $hasCommand) {
            throw "Verification phase '$($phase.id)' must define either entryScript or command."
        }

        $resolvedWorkingDirectory = if ($phase.PSObject.Properties.Name.Contains("workingDirectory") -and -not [string]::IsNullOrWhiteSpace($phase.workingDirectory)) {
            Resolve-ExperimentPath -Path $phase.workingDirectory
        }
        elseif ($hasEntryScript) {
            $repoRoot
        }
        else {
            throw "Verification phase '$($phase.id)' must set workingDirectory for direct commands."
        }

        $resolvedScriptPath = $null
        $phaseKind = if ($hasEntryScript) { "entryScript" } else { "command" }
        if ($hasEntryScript) {
            if (-not $entryScripts.PSObject.Properties.Name.Contains($phase.entryScript)) {
                throw "Verification phase '$($phase.id)' references unknown entry script '$($phase.entryScript)'."
            }

            $resolvedScriptPath = $entryScripts.$($phase.entryScript)
        }

        $arguments = if ($phase.PSObject.Properties.Name.Contains("args")) {
            @($phase.args)
        }
        else {
            @()
        }

        $normalizedPhases += [pscustomobject]@{
            Id = $phase.id
            Kind = $phaseKind
            Description = if ($phase.PSObject.Properties.Name.Contains("description")) { $phase.description } else { $null }
            EntryScriptName = if ($hasEntryScript) { $phase.entryScript } else { $null }
            ScriptPath = $resolvedScriptPath
            Command = if ($hasCommand) { $phase.command } else { $null }
            Arguments = $arguments
            WorkingDirectory = $resolvedWorkingDirectory
            TimeoutSeconds = if ($phase.PSObject.Properties.Name.Contains("timeoutSeconds")) { [int]$phase.timeoutSeconds } else { $null }
        }
    }

    $resolvedSourcePath = if ($profileData.source.PSObject.Properties.Name.Contains("checkoutPath")) {
        Resolve-ExperimentPath -Path $profileData.source.checkoutPath
    }
    elseif ($profileData.source.PSObject.Properties.Name.Contains("seedRoot")) {
        Resolve-ExperimentPath -Path $profileData.source.seedRoot
    }
    else {
        $null
    }

    $resolvedTargetRepositoryPath = Resolve-ExperimentPath -Path $profileData.target.repositoryPath
    $resolvedWorkspacePath = Resolve-ExperimentPath -Path $profileData.workspace.path
    $resolvedMaterializerScriptPath = if (
        $profileData.PSObject.Properties.Name.Contains("materializer") `
        -and $null -ne $profileData.materializer `
        -and $profileData.materializer.PSObject.Properties.Name.Contains("script") `
        -and -not [string]::IsNullOrWhiteSpace($profileData.materializer.script)
    ) {
        Resolve-ExperimentPath -Path $profileData.materializer.script
    }
    else {
        $null
    }

    return [pscustomobject]@{
        Id = $profileData.id
        DisplayName = if ($profileData.PSObject.Properties.Name.Contains("displayName")) { $profileData.displayName } else { $profileData.id }
        Description = if ($profileData.PSObject.Properties.Name.Contains("description")) { $profileData.description } else { $null }
        ProfilePath = Resolve-ExperimentProfilePath -ProfileName $ProfileName -ConfigPath $ConfigPath
        Source = [pscustomobject]@{
            Kind = $profileData.source.kind
            Path = $resolvedSourcePath
            RepositoryUrl = if ($profileData.source.PSObject.Properties.Name.Contains("repositoryUrl")) { $profileData.source.repositoryUrl } else { $null }
            DefaultBranch = if ($profileData.source.PSObject.Properties.Name.Contains("defaultBranch")) { $profileData.source.defaultBranch } else { $null }
            CheckoutPath = if ($profileData.source.PSObject.Properties.Name.Contains("checkoutPath")) { $resolvedSourcePath } else { $null }
            SeedRoot = if ($profileData.source.PSObject.Properties.Name.Contains("seedRoot")) { $resolvedSourcePath } else { $null }
        }
        SourcePath = $resolvedSourcePath
        SourceCheckoutPath = $resolvedSourcePath
        Target = [pscustomobject]@{
            Kind = $profileData.target.kind
            RepositoryPath = $resolvedTargetRepositoryPath
        }
        TargetRepositoryPath = $resolvedTargetRepositoryPath
        WorkspacePath = $resolvedWorkspacePath
        Materializer = [pscustomobject]@{
            ScriptPath = $resolvedMaterializerScriptPath
        }
        MaterializerScriptPath = $resolvedMaterializerScriptPath
        Environment = [pscustomobject]@{
            Required = $requiredEnvironment
            Optional = $optionalEnvironment
        }
        RequiredEnvironmentVariables = $requiredEnvironment
        OptionalEnvironmentVariables = $optionalEnvironment
        PrerequisiteOverlays = [pscustomobject]$prerequisiteOverlays
        VerificationPhases = $normalizedPhases
        EntryScripts = $entryScripts
    }
}

function Test-ExperimentPrerequisite {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Name,

        [Parameter(Mandatory = $true)]
        $Definition
    )

    $commandInfo = Get-Command -Name $Definition.command -ErrorAction SilentlyContinue
    $minimumVersion = if ($Definition.PSObject.Properties.Name.Contains("minimumVersion")) {
        $Definition.minimumVersion
    }
    else {
        $null
    }

    return [pscustomobject]@{
        Name = $Name
        Command = $Definition.command
        Required = [bool]$Definition.required
        MinimumVersion = $minimumVersion
        IsAvailable = $null -ne $commandInfo
        CommandPath = if ($null -ne $commandInfo) { $commandInfo.Source } else { $null }
    }
}

function Assert-ExperimentPrerequisites {
    param(
        [Parameter(Mandatory = $true)]
        $Config
    )

    $failures = @()
    foreach ($property in $Config.prerequisites.PSObject.Properties) {
        $result = Test-ExperimentPrerequisite -Name $property.Name -Definition $property.Value
        if ($result.Required -and -not $result.IsAvailable) {
            $failures += $result
        }
    }

    if ($failures.Count -gt 0) {
        $missing = $failures | ForEach-Object { "$($_.Name) [$($_.Command)]" }
        throw "Missing required prerequisites: $($missing -join ', ')"
    }
}

param(
    [string]$ConfigPath = "config/experiment.example.json",
    [string]$ProfileName = ""
)

Set-StrictMode -Version Latest
$ErrorActionPreference = "Stop"

. "$PSScriptRoot/profile-common.ps1"

function Get-PrerequisiteOverlay {
    param(
        [Parameter(Mandatory = $true)]
        $Profile,

        [Parameter(Mandatory = $true)]
        [string]$Name
    )

    if ($null -eq $Profile.PrerequisiteOverlays) {
        return $null
    }

    foreach ($property in $Profile.PrerequisiteOverlays.PSObject.Properties) {
        if ($property.Name -eq $Name) {
            return $property.Value
        }
    }

    return $null
}

function Get-PrerequisiteDefinition {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Name,

        [Parameter(Mandatory = $true)]
        $Config,

        [Parameter(Mandatory = $true)]
        $Runtime,

        [Parameter(Mandatory = $true)]
        $Profile
    )

    $baseDefinition = $Config.prerequisites.$Name
    if ($null -eq $baseDefinition) {
        throw "Experiment config is missing prerequisite definition '$Name'."
    }

    $overlay = Get-PrerequisiteOverlay -Profile $Profile -Name $Name

    $command = if ($Name -eq "python" -and $Runtime.PSObject.Properties.Name.Contains("pythonCommand") -and -not [string]::IsNullOrWhiteSpace($Runtime.pythonCommand)) {
        $Runtime.pythonCommand
    }
    elseif ($null -ne $overlay -and $overlay.PSObject.Properties.Name.Contains("command") -and -not [string]::IsNullOrWhiteSpace($overlay.command)) {
        $overlay.command
    }
    else {
        $baseDefinition.command
    }

    $required = if ($null -ne $overlay -and $overlay.PSObject.Properties.Name.Contains("required")) {
        [bool]$overlay.required
    }
    else {
        [bool]$baseDefinition.required
    }

    $minimumVersion = if ($null -ne $overlay -and $overlay.PSObject.Properties.Name.Contains("minimumVersion") -and -not [string]::IsNullOrWhiteSpace($overlay.minimumVersion)) {
        $overlay.minimumVersion
    }
    elseif ($baseDefinition.PSObject.Properties.Name.Contains("minimumVersion") -and -not [string]::IsNullOrWhiteSpace($baseDefinition.minimumVersion)) {
        $baseDefinition.minimumVersion
    }
    else {
        $null
    }

    return [pscustomobject]@{
        command = $command
        required = $required
        minimumVersion = $minimumVersion
    }
}

function Assert-ProfileOverlayCatalog {
    param(
        [Parameter(Mandatory = $true)]
        $Config,

        [Parameter(Mandatory = $true)]
        $Profile
    )

    if ($null -eq $Profile.PrerequisiteOverlays) {
        return
    }

    foreach ($overlayProperty in $Profile.PrerequisiteOverlays.PSObject.Properties) {
        $isKnownOverlay = $false
        foreach ($prerequisiteProperty in $Config.prerequisites.PSObject.Properties) {
            if ($prerequisiteProperty.Name -eq $overlayProperty.Name) {
                $isKnownOverlay = $true
                break
            }
        }

        if (-not $isKnownOverlay) {
            throw "Profile '$($Profile.Id)' references unknown prerequisite overlay '$($overlayProperty.Name)'."
        }
    }
}

function Get-ToolVersion {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Command
    )

    $output = & $Command --version 2>&1
    if ($LASTEXITCODE -ne 0) {
        throw "Failed to query version for '$Command'."
    }

    $text = ($output | Out-String).Trim()
    $match = [System.Text.RegularExpressions.Regex]::Match($text, "\d+(\.\d+)+")
    if (-not $match.Success) {
        throw "Unable to parse version from '$text'."
    }

    return [pscustomobject]@{
        Raw = $text
        Parsed = [version]$match.Value
    }
}

$config = Read-ExperimentConfig -ConfigPath $ConfigPath
$runtime = Get-ExperimentRuntimeDefaults -Config $config
$profile = Normalize-ExperimentProfile -ProfileName $ProfileName -ConfigPath $ConfigPath

Assert-ProfileOverlayCatalog -Config $config -Profile $profile

$results = @()
$failures = @()
$warnings = @()

foreach ($property in $config.prerequisites.PSObject.Properties) {
    $definition = Get-PrerequisiteDefinition -Name $property.Name -Config $config -Runtime $runtime -Profile $profile
    $availability = Test-ExperimentPrerequisite -Name $property.Name -Definition $definition
    $status = "OK"
    $detail = "available at $($availability.CommandPath)"

    if (-not $availability.IsAvailable) {
        if ($availability.Required) {
            $status = "FAIL"
            $detail = "required command '$($availability.Command)' is not available"
            $failures += "$($property.Name) [$($availability.Command)]"
        }
        else {
            $status = "WARN"
            $detail = "optional command '$($availability.Command)' is not available"
            $warnings += "$($property.Name) [$($availability.Command)]"
        }
    }
    elseif (-not [string]::IsNullOrWhiteSpace($definition.minimumVersion)) {
        $versionInfo = Get-ToolVersion -Command $availability.CommandPath
        if ($versionInfo.Parsed -lt [version]$definition.minimumVersion) {
            if ($availability.Required) {
                $status = "FAIL"
                $detail = "found version $($versionInfo.Raw); requires $($definition.minimumVersion)+"
                $failures += "$($property.Name) [$($versionInfo.Raw)]"
            }
            else {
                $status = "WARN"
                $detail = "found version $($versionInfo.Raw); optional minimum is $($definition.minimumVersion)+"
                $warnings += "$($property.Name) [$($versionInfo.Raw)]"
            }
        }
        else {
            $detail = "version $($versionInfo.Raw) satisfies $($definition.minimumVersion)+"
        }
    }

    $results += [pscustomobject]@{
        Status = $status
        Name = $property.Name
        Command = $availability.Command
        Detail = $detail
    }
}

foreach ($result in $results) {
    Write-Host ("[{0}] {1} ({2}) - {3}" -f $result.Status, $result.Name, $result.Command, $result.Detail)
}

if ($warnings.Count -gt 0) {
    Write-Warning ("Optional prerequisites unavailable or below target: {0}" -f ($warnings -join ", "))
}

if ($failures.Count -gt 0) {
    throw ("Prerequisite checks failed for profile '{0}': {1}" -f $profile.Id, ($failures -join ", "))
}

Write-Host ("All required prerequisites are available for profile '{0}'." -f $profile.Id)

param(
    [string]$ConfigPath = "config/experiment.example.json",
    [string]$ProfileName = "",
    [string]$UpstreamUrl = "",
    [string]$Branch = ""
)

Set-StrictMode -Version Latest
$ErrorActionPreference = "Stop"

. "$PSScriptRoot/profile-common.ps1"

function Get-PrerequisiteOverlay {
    param(
        [Parameter(Mandatory = $true)]
        $Profile,

        [Parameter(Mandatory = $true)]
        [string]$Name
    )

    if ($null -eq $Profile.PrerequisiteOverlays) {
        return $null
    }

    foreach ($property in $Profile.PrerequisiteOverlays.PSObject.Properties) {
        if ($property.Name -eq $Name) {
            return $property.Value
        }
    }

    return $null
}

function Get-PrerequisiteCommand {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Name,

        [Parameter(Mandatory = $true)]
        $Config,

        [Parameter(Mandatory = $true)]
        $Runtime,

        [Parameter(Mandatory = $true)]
        $Profile
    )

    $baseDefinition = $Config.prerequisites.$Name
    if ($null -eq $baseDefinition) {
        throw "Experiment config is missing prerequisite definition '$Name'."
    }

    if ($Name -eq "python" -and $Runtime.PSObject.Properties.Name.Contains("pythonCommand") -and -not [string]::IsNullOrWhiteSpace($Runtime.pythonCommand)) {
        return $Runtime.pythonCommand
    }

    $overlay = Get-PrerequisiteOverlay -Profile $Profile -Name $Name
    if ($null -ne $overlay -and $overlay.PSObject.Properties.Name.Contains("command") -and -not [string]::IsNullOrWhiteSpace($overlay.command)) {
        return $overlay.command
    }

    return $baseDefinition.command
}

function Invoke-ExternalCommand {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Command,

        [Parameter(Mandatory = $true)]
        [string[]]$Arguments,

        [Parameter(Mandatory = $true)]
        [string]$Description
    )

    Write-Host ("==> {0}" -f $Description)
    & $Command @Arguments
    if ($LASTEXITCODE -ne 0) {
        throw ("{0} failed with exit code {1}." -f $Description, $LASTEXITCODE)
    }
}

function Get-PythonVersion {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Command
    )

    $output = & $Command --version 2>&1
    if ($LASTEXITCODE -ne 0) {
        throw "Failed to query Python version for '$Command'."
    }

    $text = ($output | Out-String).Trim()
    $match = [System.Text.RegularExpressions.Regex]::Match($text, "\d+(\.\d+)+")
    if (-not $match.Success) {
        throw "Unable to parse Python version from '$text'."
    }

    return [version]$match.Value
}

function Reset-Directory {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Path
    )

    if (Test-Path -LiteralPath $Path) {
        Remove-Item -LiteralPath $Path -Recurse -Force
    }
}

$checkScriptPath = Join-Path $PSScriptRoot "check-prereqs.ps1"
& $checkScriptPath -ConfigPath $ConfigPath -ProfileName $ProfileName

$config = Read-ExperimentConfig -ConfigPath $ConfigPath
$paths = Get-ExperimentPaths -Config $config
$runtime = Get-ExperimentRuntimeDefaults -Config $config
$profile = Normalize-ExperimentProfile -ProfileName $ProfileName -ConfigPath $ConfigPath

if ($profile.Source.Kind -ne "remoteGit") {
    throw "Bootstrap only supports remoteGit profiles. Received '$($profile.Source.Kind)' for profile '$($profile.Id)'."
}

$gitCommand = Get-PrerequisiteCommand -Name "git" -Config $config -Runtime $runtime -Profile $profile
$pythonCommand = Get-PrerequisiteCommand -Name "python" -Config $config -Runtime $runtime -Profile $profile

$resolvedUpstreamUrl = if (-not [string]::IsNullOrWhiteSpace($UpstreamUrl)) {
    $UpstreamUrl
}
else {
    $profile.Source.RepositoryUrl
}

$resolvedBranch = if (-not [string]::IsNullOrWhiteSpace($Branch)) {
    $Branch
}
else {
    $profile.Source.DefaultBranch
}

$checkoutPath = $profile.Source.CheckoutPath
if ([string]::IsNullOrWhiteSpace($checkoutPath)) {
    throw "Profile '$($profile.Id)' is missing a source checkout path."
}

$checkoutParent = Split-Path -Path $checkoutPath -Parent
$localRoot = $paths.localRoot
$logsRoot = $paths.logsRoot
$workspacePath = $profile.WorkspacePath
$targetRepositoryParent = Split-Path -Path $profile.TargetRepositoryPath -Parent
$venvPath = Resolve-ExperimentPath -Path $runtime.venvPath
$venvPython = Join-Path $venvPath "Scripts/python.exe"
$pipCachePath = Join-Path $localRoot "pip-cache"

foreach ($directory in @($localRoot, $checkoutParent, $logsRoot, $workspacePath, $targetRepositoryParent, $pipCachePath)) {
    New-Item -ItemType Directory -Force -Path $directory | Out-Null
}

$checkoutGitDirectory = Join-Path $checkoutPath ".git"
if (-not (Test-Path -LiteralPath $checkoutPath)) {
    Invoke-ExternalCommand -Command $gitCommand -Arguments @("clone", "--branch", $resolvedBranch, "--single-branch", $resolvedUpstreamUrl, $checkoutPath) -Description "Clone upstream repository"
}
else {
    if (-not (Test-Path -LiteralPath $checkoutGitDirectory)) {
        Write-Warning "Existing upstream checkout is not a git repository. Recreating it."
        Reset-Directory -Path $checkoutPath
        Invoke-ExternalCommand -Command $gitCommand -Arguments @("clone", "--branch", $resolvedBranch, "--single-branch", $resolvedUpstreamUrl, $checkoutPath) -Description "Clone upstream repository"
    }
    else {
        Invoke-ExternalCommand -Command $gitCommand -Arguments @("-C", $checkoutPath, "remote", "set-url", "origin", $resolvedUpstreamUrl) -Description "Update upstream origin"
        Invoke-ExternalCommand -Command $gitCommand -Arguments @("-C", $checkoutPath, "fetch", "--prune", "origin") -Description "Fetch upstream repository"
        Invoke-ExternalCommand -Command $gitCommand -Arguments @("-C", $checkoutPath, "checkout", "-B", $resolvedBranch, "origin/$resolvedBranch") -Description "Align local branch with upstream"
        Invoke-ExternalCommand -Command $gitCommand -Arguments @("-C", $checkoutPath, "reset", "--hard", "origin/$resolvedBranch") -Description "Reset checkout to upstream state"
        Invoke-ExternalCommand -Command $gitCommand -Arguments @("-C", $checkoutPath, "clean", "-fdx") -Description "Remove untracked upstream files"
    }
}

$basePythonVersion = Get-PythonVersion -Command $pythonCommand
$recreateVenv = -not (Test-Path -LiteralPath $venvPython)
if (-not $recreateVenv) {
    try {
        $venvPythonVersion = Get-PythonVersion -Command $venvPython
        if ($venvPythonVersion.Major -ne $basePythonVersion.Major -or $venvPythonVersion.Minor -ne $basePythonVersion.Minor) {
            $recreateVenv = $true
        }
    }
    catch {
        $recreateVenv = $true
    }
}

if ($recreateVenv) {
    Write-Host "Recreating repo-local virtual environment."
    Reset-Directory -Path $venvPath
    Invoke-ExternalCommand -Command $pythonCommand -Arguments @("-m", "venv", $venvPath) -Description "Create repo-local virtual environment"
}
else {
    Write-Host "Reusing existing repo-local virtual environment."
}

$env:PIP_CACHE_DIR = $pipCachePath
Invoke-ExternalCommand -Command $venvPython -Arguments @("-m", "pip", "install", "--editable", $checkoutPath) -Description "Install upstream package in editable mode"

Write-Host ("Bootstrap complete for profile '{0}'. Upstream checkout: {1}" -f $profile.Id, $checkoutPath)
Write-Host ("Bootstrap complete for profile '{0}'. Virtual environment: {1}" -f $profile.Id, $venvPath)

param(
    [string]$ConfigPath = "config/experiment.example.json",
    [string]$ProfileName = "sample-local",
    [string]$DestinationPath = ""
)

Set-StrictMode -Version Latest
$ErrorActionPreference = "Stop"

. "$PSScriptRoot/common.ps1"

function Clear-MaterializedRepository {
    param(
        [Parameter(Mandatory = $true)]
        [string]$RepositoryPath
    )

    if (-not (Test-Path -LiteralPath $RepositoryPath)) {
        return
    }

    foreach ($item in Get-ChildItem -LiteralPath $RepositoryPath -Force) {
        if ($item.Name -eq ".git") {
            continue
        }

        Remove-Item -LiteralPath $item.FullName -Recurse -Force
    }
}

$config = Read-ExperimentConfig -ConfigPath $ConfigPath
Assert-ExperimentPrerequisites -Config $config

$profile = Normalize-ExperimentProfile -ProfileName $ProfileName -ConfigPath $ConfigPath
if ($profile.Source.Kind -ne "fixtureSeed") {
    throw "Sample materialization requires a fixtureSeed profile, got '$($profile.Source.Kind)'."
}

$seedRoot = $profile.Source.SeedRoot
$targetRepository = if ([string]::IsNullOrWhiteSpace($DestinationPath)) {
    $profile.TargetRepositoryPath
}
else {
    Resolve-ExperimentPath -Path $DestinationPath
}

if (-not (Test-Path -LiteralPath $seedRoot)) {
    throw "Sample seed not found: $seedRoot"
}

New-Item -ItemType Directory -Path $targetRepository -Force | Out-Null
New-Item -ItemType Directory -Path $profile.WorkspacePath -Force | Out-Null
Clear-MaterializedRepository -RepositoryPath $targetRepository

foreach ($item in Get-ChildItem -LiteralPath $seedRoot -Force) {
    Copy-Item -LiteralPath $item.FullName -Destination (Join-Path $targetRepository $item.Name) -Recurse -Force
}

$gitDirectory = Join-Path $targetRepository ".git"
if (-not (Test-Path -LiteralPath $gitDirectory)) {
    & git -C $targetRepository init --quiet | Out-Null
}

Write-Output $targetRepository

